 40→describe("auth e2e", () => {
 41→	test("login: callback server receives token and stores credentials", async () => {
 42→		// Clear any existing credentials first
 43→		clearCredentialsFromDir(configDir);
 44→
 45→		const cliPath = join(import.meta.dir, "..", "bin", "cli.ts");
 46→		const stdoutLogPath = join(tempDir, "login-stdout.log");
 47→
 48→		// Start login via shell, tee stdout to a file so we can poll it
 49→		const loginProcess = Bun.spawn(
 50→			[
 51→				"bash",
 52→				"-c",
 53→				`bun "${cliPath}" login --api-base="${server.baseUrl}" --web-url=http://localhost:9999 2>&1 | tee "${stdoutLogPath}"`,
 54→			],
 55→			{
 56→				env: {
 57→					...process.env,
 58→					RUDEL_CONFIG_DIR: configDir,
 59→				},
 60→				stdout: "pipe",
 61→				stderr: "pipe",
 62→			},
 63→		);
 64→
 65→		// Poll the log file for the "Opening browser" message
 66→		const { readFileSync, existsSync } = require("node:fs");
 67→		let output = "";
 68→		const deadline = Date.now() + 10_000;
 69→
 70→		while (Date.now() < deadline) {
 71→			if (existsSync(stdoutLogPath)) {
 72→				output = readFileSync(stdoutLogPath, "utf-8");
 73→				if (output.includes("Opening browser")) break;
 74→			}
 75→			await Bun.sleep(100);
 76→		}
 77→
 78→		// Extract the callback URL from the output
 79→		const callbackMatch = output.match(/cli_callback=([^&]+)/);
 80→		expect(callbackMatch).not.toBeNull();
 81→		const callbackUrl = decodeURIComponent(callbackMatch?.[1] ?? "");
 82→
 83→		// Extract the state
 84→		const stateMatch = output.match(/state=([a-f0-9]+)/);
 85→		expect(stateMatch).not.toBeNull();
 86→		const state = stateMatch?.[1] ?? "";
 87→
 88→		// Simulate what the web app does: hit the callback with token + state
 89→		const callbackResponse = await fetch(
 90→			`${callbackUrl}?token=${sessionToken}&state=${state}`,
 91→		);
 92→		expect(callbackResponse.ok).toBe(true);
 93→		const callbackBody = await callbackResponse.text();
 94→		expect(callbackBody).toContain("Login successful");
 95→
 96→		// Wait for the process to finish
 97→		const exitCode = await loginProcess.exited;
 98→		expect(exitCode).toBe(0);
 99→
100→		// Verify credentials were stored
101→		const savedCredentials = loadCredentialsFromDir(configDir);
102→		expect(savedCredentials).not.toBeNull();
103→		expect(savedCredentials?.token).toBe(sessionToken);
104→		expect(savedCredentials?.apiBaseUrl).toBe(server.baseUrl);
105→	});
