 97→// ClickHouse Cloud's @clickhouse/client insert() silently drops data.
 98→// Wrap the executor to use execute() with FORMAT JSONEachRow instead.
 99→// async_insert=0 forces synchronous insert so data is immediately queryable.
100→const executor: typeof baseExecutor = {
101→	...baseExecutor,
102→	async insert(params) {
103→		const rows = params.values.map((r) => JSON.stringify(r)).join("\n");
104→		await baseExecutor.execute(
105→			`INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
106→		);
107→	},
108→};
