164→		};
165→
166→		// ClickHouse Cloud can silently drop inserts or throw race condition
167→		// errors (code 236). Retry the insert+read cycle with exponential backoff.
168→		let results: Awaited<ReturnType<typeof waitForRow>> = [];
169→		for (let attempt = 0; attempt < 5; attempt++) {
