 31→async function waitForQuery<T>(
 32→	query: string,
 33→	timeoutMs = 30000,
 34→	intervalMs = 2000,
 35→): Promise<T[]> {
 36→	const start = Date.now();
 37→	while (Date.now() - start < timeoutMs) {
 38→		try {
 39→			const results = await executor.query<T>(query);
 40→			if (results.length > 0) return results;
 41→		} catch {
 42→			// Transient ClickHouse errors (e.g. S3 storage) - retry
 43→		}
 44→		await new Promise((r) => setTimeout(r, intervalMs));
 45→	}
 46→	return [];
 47→}
 48→
 49→async function insertWithRetry(
 50→	fn: () => Promise<void>,
 51→	queryFn: () => Promise<unknown[]>,
 52→	maxAttempts = 5,
 53→): Promise<unknown[]> {
 54→	for (let attempt = 0; attempt < maxAttempts; attempt++) {
 55→		try {
 56→			await fn();
 57→		} catch (error) {
 58→			// Retry on transient ClickHouse errors (e.g. INSERT race conditions)
 59→			if (attempt === maxAttempts - 1) throw error;
 60→			await new Promise((r) => setTimeout(r, 2000 * 2 ** attempt));
 61→			continue;
 62→		}
 63→		const results = await queryFn();
 64→		if (results.length > 0) return results;
 65→	}
 66→	return [];
 67→}
